var knownOfficeSlugMap = map[string]string{
	"ceo":        "hybridCeo",
	"pm":         "hybridPm",
	"fe":         "hybridFe",
	"frontend":   "hybridFe",
	"be":         "hybridBe",
	"backend":    "hybridBe",
	"eng":        "hybridEng",
	"gtm":        "hybridGtm",
	"ai":         "hybridAi",
	"ai-eng":     "hybridAi",
	"ai_eng":     "hybridAi",
	"designer":   "hybridDesigner",
	"cmo":        "hybridCmo",
	"cro":        "hybridCro",
	"pam":        "hybridPam",
	"pamcute":    "hybridPamCute",
	"pam-cute":   "hybridPamCute",
	"pam-soft":   "hybridPamCute",
	"pam-legacy": "hybridPamCute",
	"human":      "hybridHuman",
	"you":        "hybridHuman",
	"nex":        "hybridNex",
	"generic":    "hybridGeneric",
	"qa":         "hybridQa",
	"ae":         "hybridAe",
	"sdr":        "hybridSdr",
	"research":   "hybridResearch",
	"content":    "hybridContent",
}

func knownOfficeSpriteForSlug(slug string) (knownOfficeSprite, bool) {
	key, ok := knownOfficeSlugMap[strings.ToLower(slug)]
	if !ok {
		return knownOfficeSprite{}, false
	}
	sprite, ok := knownOfficeSprites[key]
	return sprite, ok
}
